<svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Desplome del Kospi vs. Aumento del Volumen de Upbit — 13 de Julio</text>
  <text x="20" y="50" fill="#71717a" font-size="12" font-family="sans-serif">Recopilado de MEXC News/CryptoRank.io, cryptonews.net, CoinDesk, Odaily</text>
  <text x="180" y="80" fill="#fca5a5" font-family="sans-serif" font-size="13" font-weight="700" text-anchor="middle">Kospi (Acciones)</text>
